Here's how to write modern MSTest tests for `DataFetcher` with proper timeout and cancellation handling:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync("http://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.NotFound));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("http://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange - handler that delays forever
        var handler = new FakeHandler(neverCompletes: true);
        var fetcher = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("http://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(2000)]
    public async Task FetchAsync_TimeoutExpires_IsCancelledCooperatively()
    {
        // Arrange - handler that delays longer than the timeout
        var handler = new FakeHandler(delay: TimeSpan.FromSeconds(10));
        var fetcher = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(100));

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("http://example.com", cts.Token));
    }

    // Minimal fake handler for testing
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage? _response;
        private readonly TimeSpan _delay;
        private readonly bool _neverCompletes;

        public FakeHandler(HttpResponseMessage response, TimeSpan delay = default)
        {
            _response = response;
            _delay = delay;
        }

        public FakeHandler(bool neverCompletes) => _neverCompletes = neverCompletes;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_neverCompletes)
            {
                await Task.Delay(Timeout.Infinite, cancellationToken);
            }

            if (_delay > TimeSpan.Zero)
            {
                await Task.Delay(_delay, cancellationToken);
            }

            cancellationToken.ThrowIfCancellationRequested();
            return _response!;
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Why |
|---------|-----|
| `TestContext` via constructor | Enables `readonly`, satisfies nullability |
| `[Timeout(N)]` + `_testContext.CancellationToken` | Cooperative timeout — test is cancelled cleanly if it hangs |
| `Assert.ThrowsExactlyAsync<T>` | Verifies exact exception type with proper async unwrapping |
| `FakeHandler` | Avoids real HTTP; gives full control over delays and responses |
| `CancellationTokenSource` with timeout | Simulates caller-driven cancellation independently of `[Timeout]` |

The `[Timeout]` attribute signals the cancellation token from `TestContext`, so always pass `_testContext.CancellationToken` into your production code under test. This ensures hung tests don't block your entire test run.
